import{c as i,S as h,j as t,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Quản lý tiêu chí đề thi","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/quan-ly-tieu-chi.md","filePath":"giao-vien/quan-ly-tieu-chi.md","lastUpdated":0}'),c={name:"giao-vien/quan-ly-tieu-chi.md"};function o(l,n,u,r,g,e){return h(),t("div",null,[...n[0]||(n[0]=[a('<h1 id="quan-ly-tieu-chi-đe-thi" tabindex="-1">Quản lý tiêu chí đề thi <a class="header-anchor" href="#quan-ly-tieu-chi-đe-thi" aria-label="Permalink to “Quản lý tiêu chí đề thi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/teacher/criteria</code></p><p>Tiêu chí đề thi (Criteria) cho phép bạn cấu hình <strong>&quot;công thức&quot;</strong> để hệ thống <strong>tự sinh đề ngẫu nhiên</strong> từ ngân hàng câu hỏi. Mỗi lần học viên làm bài, đề có thể khác nhau (tránh truyền tay đáp án).</p><h2 id="khai-niem" tabindex="-1">Khái niệm <a class="header-anchor" href="#khai-niem" aria-label="Permalink to “Khái niệm”">​</a></h2><p>Một tiêu chí mô tả:</p><ul><li><strong>Lấy bao nhiêu câu hỏi</strong>?</li><li><strong>Từ chuyên đề / chủ đề nào</strong>?</li><li><strong>Mức độ khó như thế nào</strong>?</li><li><strong>Thuộc dạng nào</strong> (lý thuyết, vận dụng, vận dụng cao)?</li></ul><p>Ví dụ:</p><blockquote><p>&quot;Đề kiểm tra Toán chương Hàm số, 30 câu, 10 câu nhận biết + 15 câu thông hiểu + 5 câu vận dụng.&quot;</p></blockquote><h2 id="danh-sach-tieu-chi" tabindex="-1">Danh sách tiêu chí <a class="header-anchor" href="#danh-sach-tieu-chi" aria-label="Permalink to “Danh sách tiêu chí”">​</a></h2><p>Cột chính:</p><ul><li>Tên tiêu chí</li><li>Khóa học áp dụng</li><li>Tổng số câu / Tổng điểm</li><li>Người tạo</li><li>Trạng thái</li></ul><h2 id="tao-tieu-chi" tabindex="-1">Tạo tiêu chí <a class="header-anchor" href="#tao-tieu-chi" aria-label="Permalink to “Tạo tiêu chí”">​</a></h2><ol><li>Bấm <strong>Thêm tiêu chí</strong>.</li><li>Điền: <ul><li><strong>Tên tiêu chí</strong> (vd: &quot;Đề KT chuyên đề Hàm số&quot;)</li><li><strong>Khóa học / chuyên đề</strong> liên kết</li><li><strong>Tổng số câu</strong>, <strong>Tổng điểm</strong></li></ul></li><li><strong>Thêm dòng tiêu chí con</strong>: <ul><li><strong>Chương / Chuyên đề</strong> (chọn từ danh mục)</li><li><strong>Mức độ</strong> (Nhận biết / Thông hiểu / Vận dụng / Vận dụng cao)</li><li><strong>Loại câu hỏi</strong> (Trắc nghiệm 4 đáp án / Điền số / Đúng-sai / ...)</li><li><strong>Số câu cần lấy</strong></li><li><strong>Điểm mỗi câu</strong></li></ul></li><li>Có thể thêm nhiều dòng tiêu chí (vd 3 mức khó × 4 chuyên đề).</li><li><strong>Tổng số câu các dòng phải = Tổng số câu của đề</strong>.</li><li>Lưu.</li></ol><h2 id="su-dung-tieu-chi-khi-tao-đe-thi" tabindex="-1">Sử dụng tiêu chí khi tạo đề thi <a class="header-anchor" href="#su-dung-tieu-chi-khi-tao-đe-thi" aria-label="Permalink to “Sử dụng tiêu chí khi tạo đề thi”">​</a></h2><ol><li>Vào tạo <strong>Đề kiểm tra cuối chuyên đề</strong> hoặc <strong>Đề ôn khóa học</strong>.</li><li>Chọn cách <strong>Tạo theo tiêu chí</strong> thay vì chọn câu thủ công.</li><li>Chọn <strong>Tiêu chí</strong> từ danh sách.</li><li>(Tùy chọn) <strong>Random mới mỗi lần học viên làm bài</strong> - hệ thống tự rút câu mới.</li><li>Lưu đề.</li></ol><h2 id="tieu-chi-cho-cac-ky-thi-đac-thu" tabindex="-1">Tiêu chí cho các kỳ thi đặc thù <a class="header-anchor" href="#tieu-chi-cho-cac-ky-thi-đac-thu" aria-label="Permalink to “Tiêu chí cho các kỳ thi đặc thù”">​</a></h2><h3 id="đgnl-hsa" tabindex="-1">ĐGNL (HSA) <a class="header-anchor" href="#đgnl-hsa" aria-label="Permalink to “ĐGNL (HSA)”">​</a></h3><ul><li>Tạo 3 nhóm tiêu chí cho 3 phần: Tư duy định lượng, Tư duy định tính, Khoa học.</li><li>Mỗi phần cấu hình số câu, mức khó.</li></ul><h3 id="đgtd-tsa" tabindex="-1">ĐGTD (TSA) <a class="header-anchor" href="#đgtd-tsa" aria-label="Permalink to “ĐGTD (TSA)”">​</a></h3><ul><li>Tạo tiêu chí cho từng phần: Toán học, Đọc hiểu, Giải quyết vấn đề.</li></ul><h3 id="tnthpt-tung-mon" tabindex="-1">TNTHPT từng môn <a class="header-anchor" href="#tnthpt-tung-mon" aria-label="Permalink to “TNTHPT từng môn”">​</a></h3><ul><li>Cấu hình theo cấu trúc đề minh họa Bộ GD&amp;ĐT.</li><li>VD Toán 50 câu: 15 nhận biết + 20 thông hiểu + 10 vận dụng + 5 vận dụng cao.</li></ul><blockquote><p>💡 Các tiêu chí mẫu sẵn có cho HSA / TSA / TNTHPT thường do Admin tạo và chia sẻ. Hãy hỏi Admin trước khi tự xây từ đầu.</p></blockquote><h2 id="kiem-tra-tieu-chi" tabindex="-1">Kiểm tra tiêu chí <a class="header-anchor" href="#kiem-tra-tieu-chi" aria-label="Permalink to “Kiểm tra tiêu chí”">​</a></h2><p>Sau khi tạo, bấm <strong>Xem thử</strong> để hệ thống sinh thử 1 đề ngẫu nhiên dựa trên tiêu chí. Kiểm tra:</p><ul><li>Số câu có đúng không?</li><li>Câu hỏi lấy có đúng chuyên đề / mức khó không?</li><li>Có câu trùng / câu lỗi không?</li></ul><h2 id="sua-xoa" tabindex="-1">Sửa / Xóa <a class="header-anchor" href="#sua-xoa" aria-label="Permalink to “Sửa / Xóa”">​</a></h2><ul><li><strong>Sửa</strong>: thay đổi áp dụng cho <strong>đề tạo mới</strong>. Các đề đã có vẫn giữ nguyên câu hỏi đã rút.</li><li><strong>Xóa</strong>: chỉ xóa được khi không có đề thi nào đang dùng.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên báo &quot;đề chỉ có 28 câu thay vì 30&quot;.</strong> → Có thể ngân hàng câu hỏi thiếu câu thỏa điều kiện. Mở tiêu chí, giảm yêu cầu (vd: vận dụng cao chỉ 3 thay vì 5) hoặc bổ sung thêm câu vào ngân hàng.</p><p><strong>Tôi muốn cùng 1 đề cho mọi học viên, không random.</strong> → Không dùng tiêu chí. Chọn cách <strong>Tạo đề thủ công</strong> và chọn từng câu cụ thể.</p><p><strong>Có cách nào &quot;chỉ lấy câu mà học viên chưa từng làm&quot; không?</strong> → Tùy phiên bản hệ thống. Một số hệ thống bật <strong>Adaptive testing</strong> để loại câu đã xuất hiện gần đây. Hỏi Admin.</p>',32)])])}const m=i(c,[["render",o]]);export{d as __pageData,m as default};
